import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getSaleById, updateSale } from "../../api/saleApi";

export default function EditPayment() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [loading, setLoading] = useState(true);

  const [form, setForm] = useState({
    dealStatus: "initiated",
    paymentStatus: "pending",
    quotedPrice: "",
    finalPrice: "",
    paidAmount: 0,
    paymentMethod: "cash",
    notes: "",
  });

  useEffect(() => {
    const load = async () => {
      try {
        const res = await getSaleById(id);
        const s = res.data;

        setForm({
          dealStatus: s.dealStatus || "initiated",
          paymentStatus: s.paymentStatus || "pending",
          quotedPrice: s.quotedPrice ?? "",
          finalPrice: s.finalPrice ?? "",
          paidAmount: s.paidAmount ?? 0,
          paymentMethod: s.paymentMethod || "cash",
          notes: s.notes || "",
        });
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load transaction");
        navigate("/sales");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [id, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;

    // keep numbers as numbers where needed
    if (name === "quotedPrice" || name === "finalPrice" || name === "paidAmount") {
      setForm((prev) => ({ ...prev, [name]: value === "" ? "" : Number(value) }));
      return;
    }

    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const submit = async (e) => {
    e.preventDefault();

    // basic validation
    if (form.finalPrice !== "" && form.finalPrice < 0) return alert("Final price cannot be negative");
    if (form.paidAmount !== "" && form.paidAmount < 0) return alert("Paid amount cannot be negative");

    try {
      await updateSale(id, form);
      alert("Transaction updated!");
      navigate("/sales");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  if (loading) return <p style={{ padding: 20 }}>Loading...</p>;

  return (
    <div style={{ padding: 20, maxWidth: 560 }}>
      <h2>Edit Payment / Transaction</h2>

      <form onSubmit={submit}>
        <label>Deal Status</label><br />
        <select
          name="dealStatus"
          value={form.dealStatus}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="initiated">Initiated</option>
          <option value="completed">Completed</option>
          <option value="cancelled">Cancelled</option>
        </select>

        <br /><br />

        <label>Payment Status</label><br />
        <select
          name="paymentStatus"
          value={form.paymentStatus}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="pending">Pending</option>
          <option value="partial">Partial</option>
          <option value="paid">Paid</option>
          <option value="refunded">Refunded</option>
        </select>

        <br /><br />

        <label>Quoted Price</label><br />
        <input
          name="quotedPrice"
          type="number"
          value={form.quotedPrice}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Final Price</label><br />
        <input
          name="finalPrice"
          type="number"
          value={form.finalPrice}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Paid Amount</label><br />
        <input
          name="paidAmount"
          type="number"
          value={form.paidAmount}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Payment Method</label><br />
        <select
          name="paymentMethod"
          value={form.paymentMethod}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="cash">Cash</option>
          <option value="bank_transfer">Bank Transfer</option>
          <option value="card">Card</option>
          <option value="cheque">Cheque</option>
          <option value="other">Other</option>
        </select>

        <br /><br />

        <label>Notes</label><br />
        <textarea
          name="notes"
          rows={3}
          value={form.notes}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <button style={{ padding: "10px 14px" }}>Save</button>
      </form>
    </div>
  );
}
